fn token(sum: i32, slot: usize, packed: bool, group: bool, reuse: bool) -> i32 {
    let mut v = sum + (slot as i32) * 7;
    if packed { v += 3; }
    if group { v += 5; }
    if reuse { v += 11; }
    v.rem_euclid(101)
}

fn render_nums(a: &[i32]) -> String {
    a.iter().map(|x| x.to_string()).collect::<Vec<_>>().join(",")
}

fn render_usize(a: &[usize]) -> String {
