package main

import (
	"encoding/json"
	"os"
	"reflect"
)

type entry struct {
	Case      string `json:"case"`
	Produced  []int  `json:"produced"`
	Trace     []int  `json:"slot_trace"`
	OrderUsed []int  `json:"order_used"`
	Packed    bool   `json:"packed"`
	Grouped   bool   `json:"grouped"`
	Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
	Raw []entry `json:"raw"`
}

type finalDoc struct {
	Rows    []entry `json:"rows"`
	Summary summary `json:"summary"`
}

type summary struct {
	Total int  `json:"total"`
	Agree bool `json:"agree"`
}

func matches(a, b entry) bool {
	if a.Case != b.Case {
		return false
	}
	if !reflect.DeepEqual(a.Produced, b.Produced) {
		return false
	}
	if !reflect.DeepEqual(a.Trace, b.Trace) {
		return false
	}
	if !reflect.DeepEqual(a.OrderUsed, b.OrderUsed) {
		return false
	}
	if a.Packed != b.Packed {
		return false
	}
	if a.Grouped != b.Grouped {
		return false
	}
	if a.Reuse != b.Reuse {
		return false
	}
	return true
}

func main() {
	if len(os.Args) != 3 {
		panic("usage: align raw final")
	}
	buf, err := os.ReadFile(os.Args[1])
	if err != nil {
		panic(err)
	}
	var raw rawDoc
	if err := json.Unmarshal(buf, &raw); err != nil {
		panic(err)
	}

	// Build report rows as copies of raw rows
	reportRows := make([]entry, len(raw.Raw))
	copy(reportRows, raw.Raw)

	// Check agreement
	agree := true

	// If a prior report.json exists, compare incoming raw against stored report
	outPath := os.Args[2]
	if priorBuf, err := os.ReadFile(outPath); err == nil {
		var prior finalDoc
		if err := json.Unmarshal(priorBuf, &prior); err == nil {
			// Build map of prior report rows by case name
			priorMap := map[string]entry{}
			for _, row := range prior.Rows {
				priorMap[row.Case] = row
			}
			// Compare each raw row against prior report row
			for _, rawRow := range raw.Raw {
				priorRow, exists := priorMap[rawRow.Case]
				if !exists {
					agree = false
					break
				}
				if !matches(rawRow, priorRow) {
					agree = false
					break
				}
			}
			// Also check if prior had cases not in raw
			if agree {
				rawMap := map[string]entry{}
				for _, r := range raw.Raw {
					rawMap[r.Case] = r
				}
				for _, pr := range prior.Rows {
					if _, exists := rawMap[pr.Case]; !exists {
						agree = false
						break
					}
				}
			}
			// Check row counts match
			if agree && len(prior.Rows) != len(raw.Raw) {
				agree = false
			}
		} else {
			agree = false
		}
	}
	// No prior file: report rows == raw rows, so agree is true

	doc := finalDoc{
		Rows:    reportRows,
		Summary: summary{Total: len(reportRows), Agree: agree},
	}
	out, err := json.MarshalIndent(doc, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.WriteFile(outPath, append(out, '\n'), 0o644); err != nil {
		panic(err)
	}
}
